<header class="page-head"><div><span class="eyebrow">Katalog</span><h1>Produk</h1></div><a class="button" href="<?=url('/admin/products/create')?>">Tambah produk</a></header><section class="panel"><div class="table-wrap" tabindex="0" aria-label="Daftar produk, geser horizontal bila diperlukan"><table><thead><tr><th>Produk</th><th>Kategori</th><th>Harga</th><th>Varian</th><th>Stok</th><th>Aksi</th></tr></thead><tbody><?php foreach($items as $x):?><tr><td><strong><?=e($x['name'])?></strong><small><?=e($x['base_sku'])?></small></td><td><?=e($x['category_name']??'—')?></td><td><?=money($x['base_price'])?></td><td><?=$x['variant_count']?></td><td><?=$x['stock']??0?></td><td class="actions"><a class="table-action" href="<?=url('/admin/products/'.$x['id'].'/edit')?>">Edit</a><form method="post" action="<?=url('/admin/products/'.$x['id'])?>" onsubmit="return confirm('Nonaktifkan produk ini? Produk tidak akan tampil di toko.')"><?=csrf_field()?><input type="hidden" name="_method" value="DELETE"><button class="link-danger">Nonaktifkan</button></form></td></tr><?php endforeach?><?php if(!$items):?><tr><td colspan="6" class="empty-cell">Belum ada produk. <a href="<?=url('/admin/products/create')?>">Tambah produk pertama</a>.</td></tr><?php endif?></tbody></table></div></section>
